/**
 * 벤치마크 조회
 * @param leadTimeDays 현재 리드타임 (일)
 * @returns expected OCC (0-1) 또는 null (데이터 없음)
 */
export function getExpectedOcc(
  branchName: string,
  roomType: string,
  month: number,
  dowType: 'weekday' | 'weekend',
  leadTimeDays: number
): number | null {
  const key = `${branchName}|${roomType}|${month}|${dowType}`
  const curve = PACE_BENCHMARKS[key]
  if (!curve) return null

  // 정확한 버킷이 있으면 반환
  if (curve[leadTimeDays] !== undefined) return curve[leadTimeDays]

  // 가장 가까운 버킷에서 보간
  const buckets = Object.keys(curve).map(Number).sort((a, b) => a - b)
  if (buckets.length === 0) return null

  // 범위 밖이면 경계값 반환
  if (leadTimeDays <= buckets[0]) return curve[buckets[0]]
  if (leadTimeDays >= buckets[buckets.length - 1]) return curve[buckets[buckets.length - 1]]

  // 선형 보간
  for (let i = 0; i < buckets.length - 1; i++) {
    if (leadTimeDays >= buckets[i] && leadTimeDays <= buckets[i + 1]) {
      const ratio = (leadTimeDays - buckets[i]) / (buckets[i + 1] - buckets[i])
      return curve[buckets[i]] + ratio * (curve[buckets[i + 1]] - curve[buckets[i]])
    }
  }

  return null
}
